n, m = map(int, input().split())
a = [list(map(str, input())) for _ in range(n)]


def count_bombs(a, i, j):
    cnt = 0
    for di in range(-1, 2):
        for dj in range(-1, 2):
            if di == dj == 0:
                continue
            if 0 <= i + di < n and 0 <= j + dj < m:
                cnt += (a[i + di][j + dj] == '*')
    return cnt


def check():
    for i in range(n):
        for j in range(m):
            if a[i][j] == '*':
                continue
            cnt = count_bombs(a, i, j)
            if cnt != int(a[i][j]):
                return False
    return True


print('YES' if check() else 'NO')
